import hashlib


def hash_file(filepath, algorithm='sha256', chunk_size=8192):
    """
    Creates a hash of a file for integrity checking.
    
    Args:
        filepath: Path to the file to hash
        algorithm: Hash algorithm to use (default: sha256)
        chunk_size: Size of chunks to read (default: 8192 bytes)
    
    Returns:
        Hexadecimal string representation of the file hash
    """
    hash_obj = hashlib.new(algorithm)
    
    with open(filepath, 'rb') as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            hash_obj.update(chunk)
    
    return hash_obj.hexdigest()